```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <cctype>

// Function to convert a string to lowercase
std::string toLower(const std::string& str) {
    std::string result;
    for (char c : str) {
        result += std::tolower(c);
    }
    return result;
}

int main() {
    std::string filename, word;
    int count = 0;

    // Prompt the user for the filename and the word to search for
    std::cout << "Enter the filename: ";
    std::getline(std::cin, filename);
    std::cout << "Enter the word to search for: ";
    std::getline(std::cin, word);

    // Convert the word to lowercase for case-insensitive search
    word = toLower(word);

    // Open the file for reading
    std::ifstream file(filename);
    if (file.is_open()) {
        std::string line;
        while (std::getline(file, line)) {
            // Convert the line to lowercase for case-insensitive search
            std::string lowercaseLine = toLower(line);

            // Find the starting position of the word in the line
            size_t pos = 0;
            while ((pos = lowercaseLine.find(word, pos)) != std::string::npos) {
                count++;
                pos += word.length();
            }
        }
        file.close();
        std::cout << "The word \"" << word << "\" appears " << count << " times in the file \"" << filename << "\"." << std::endl;
    } else {
        std::cout << "Unable to open the file \"" << filename << "\"." << std::endl;
    }

    return 0;
}
```

